-- 项目 4: 第一阶段：植物的悄悄话
-- 周数: 4
-- 活动数: 8
-- ============================================================

UPDATE course_contents
SET week_plan = $week_data$[{"week":1,"theme":"播种希望与爱的种子","days_range":"1-7","goals":["理解“对照实验”的基本概念。亲手种植两盆完全相同的植物，并将它们命名和分组。制作一份专门的《植物观察日记》，并开始对植物进行差异化的“爱的关注”。"],"activities":[{"sequence":1,"day_label":"Day 1-2","day_range":"1-2","title_zh":"新的任务：植物能“听”到我们的爱吗？","title_en":"New Mission: Can Plants 'Hear' Our Love?","duration":"约45分钟，可在2天内完成","content":"(任务时长：约45分钟，可在2天内完成)\n欢迎加入“伊卡洛斯计划”的第二个模块！这一次，我们的探险伙伴不再是毛茸茸的动物，而是安静、充满生命力的植物。\n你有没有想过，你每天经过的花草树木，它们能感觉到你的存在吗？如果我们对一棵植物充满爱意，对另一棵却视而不见，它们的长势会有什么不同吗？\n在很久以前，有一位名叫克里夫·巴克斯特（Cleve Backster）的专家，他平时的工作是使用一种叫做“测谎仪”的神奇机器。有一天，他突发奇想，把测谎仪的电极连接到了一盆龙舌兰植物的叶子上。\n他想看看，如果给植物浇水，测谎仪的指针会不会动。结果，指针画出了一条平缓的曲线，就像一个人感到满足时一样。\n接着，巴克斯特产生了一个“坏念头”：“我要用火柴去烧一下这片叶子！”\n他甚至还没有去找火柴，只是在脑海里刚刚产生这个想法的瞬间，测谎仪的指针突然疯狂地摆动起来，画出了剧烈的波峰，就像一个人极度恐惧时一样！\n巴克斯特惊呆了。难道……植物能“读”出他的思想？\n从那天起，他做了成百上千次类似的实验。他发现，植物似乎不仅能感知到直接的伤害，还能对人的意图、甚至是远方其他生命的死亡（比如将活虾丢进开水）产生“情绪”反应。\n巴克斯特的研究在当时引起了巨大的轰动和争议。很多人不相信，认为那只是巧合。但是，它也启发了无数人去重新思考：生命与生命之间，究竟存在着怎样一种我们还不知道的、深刻的连接？\n现在，轮到你了，植物守护者。我们虽然没有测谎仪，但我们有更强大的工具——爱、耐心和科学的眼睛。让我们用一个简单但严谨的实验，来亲手探索这个秘密吧！\n仔细阅读《克里夫·巴克斯特的惊人发现》的故事。\n思考：你相信植物有“感觉”或“情绪”吗？为什么？\n接受新任务： 在下方的文本框中，输入你的宣言。\n格式： “我是守护者 [你的名字]，我接受‘植物的悄悄话’任务！我相信/不相信植物有感觉，因为……”"},{"sequence":3,"day_label":"Day 3-5","day_range":"3-5","title_zh":"实验的基石：什么是“对照组”？","title_en":"The Cornerstone: What is a 'Control Group'?","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n植物守护者，如果我们只养一盆植物，每天对它说很多好话，它长得很好。我们能因此得出结论说“是好话让它长得好”吗？\n不一定。也许是因为阳光很好，或者我们浇水很勤。\n为了知道是不是某一个特定的原因（比如“爱”）起作用，科学家发明了一个超级重要的方法，叫做**“对照实验”（Controlled Experiment）**。\n方法很简单：准备两个完全一样的东西，只对其中一个做你想测试的事，另一个什么都不做。最后比较它们俩有什么不同。\n实验组 (Experimental Group): 我们对它做特别事情的那一个。在我们的实验里，就是那盆我们会对它充满爱意的植物。\n对照组 (Control Group): 我们用它来“对照”和“比较”的那一个。在我们的实验里，就是那盆我们正常照顾但不多加关注的植物。\n我们的实验设计：\n准备两盆完全相同的植物。 (可以是同一种种子，用同样的土，同样大小的花盆)\n给予它们完全相同的物理条件：\n放在同一个窗台上，确保它们得到一样的阳光。\n每次浇水，都用量杯量好，给它们浇一样多的水。\n施加唯一的“变量”——爱的关注：\n对实验组植物： 每天花5分钟，对它说鼓励的话，轻轻抚摸它的叶子，在心里想着它茁壮成长的样子。\n对对照组植物： 只是完成浇水等必要工作，不多看它，也不和它“交流”。\n如果几周后，实验组的植物真的比对照组长得更好，我们就能更有信心地说：“也许，我们‘爱的关注’真的起作用了！”\n理解为什么在科学实验中，“对照组”是必不可少的。\n动手准备： 和爸爸妈妈一起去准备你的实验材料：两颗相同的种子（比如绿豆、番茄种子）、两个相同的花盆、以及足够的土壤。\n提交你的实验材料照片：\n请将你准备好的两颗种子、两个花盆和土壤摆在一起，拍照上传。确保照片能看出它们是“完全相同”的。\n提交你的“对照思维”理解：\n在下方的文本框中回答：“如果我们只用一盆植物做实验，会有什么问题？”"},{"sequence":6,"day_label":"Day 6-7","day_range":"6-7","title_zh":"播种与命名：实验正式开始！","title_en":"Planting & Naming: The Experiment Begins!","duration":"约45分钟，可在2天内完成","content":"(任务时长：约45分钟，可在2天内完成)\n植物守护者，激动人心的时刻到了！今天，我们将亲手种下这两颗种子。\n播种： 在爸爸妈妈的帮助下，将土壤装进两个花盆，并在每个花盆的中央，以同样的深度，分别埋下一颗种子。\n浇水： 用量杯量取同样多的水，轻轻地、均匀地浇灌两盆土壤。\n分组与命名： 这是充满仪式感的一步！\n给你的植物起名字！ 一个代表着“爱与希望”，一个代表着“平静与自然”。\n制作两个小标签。一个写上你的实验组植物的名字，并在后面画一颗爱心❤️。另一个写上你的对照组植物的名字，并在后面画一片叶子  。\n将标签插在各自的花盆里。从今天起，你就要开始对它们进行“区别对待”了！\n安置： 将两盆植物并排放在同一个光照充足的地方。\n制作日记： 在你的笔记本里，创建一份新的《植物观察日记》。模板如下：\n植物观察日记 - 第 [ ] 周\n实验组：[植物名] ❤️\n对照组：[植物名]   \n日期\n（例如：2025年11月15日）\n（例如：2025年11月15日）\n今天的照片\n（在这里贴上照片或画图）\n（在这里贴上照片或画图）\n身高 (cm)\n（用尺子量，发芽前为0）\n（用尺子量，发芽前为0）\n叶片数量\n（发芽前为0）\n（发芽前为0）\n我对它做了什么？\n（例如：对它说了‘加油’，抚摸了叶子）\n（例如：只浇了20ml水）\n我的观察和感受\n（例如：感觉土壤很湿润）\n（例如：感觉土壤很湿润）\n学习如何进行简单的、标准化的测量（身高、叶片数量）。\n开始你的第一次“爱的关注”和“中性对待”的实践。\n提交你的“双胞胎”植物照片：\n请为你刚刚种好、并插上标签的两盆植物拍一张合影，拍照上传。\n提交你的第一份空白日记：\n请拍照上传你手绘的第一份空白的《植物观察日记》表格。\n太棒了，植物守护者！你已经成功地启动了你的第一个对照实验。两颗种子，承载着两种不同的期望，已经在大地母亲的怀抱中开始孕育。从下周开始，我们将进入漫长而充满期待的每日观察、记录和“沟通”阶段。你是否能用你的爱，创造一个生命的奇迹呢？让我们拭目以待！"}]},{"week":2,"theme":"爱的“灌溉”与数据的萌芽","days_range":"8-14","goals":["建立每日观察、测量和记录的固定习惯。系统地对“实验组”植物进行充满爱意的互动，对“对照组”植物进行标准化的必要照料。成功完成第一周的《植物观察日记》，并捕捉到植物从种子到萌芽的珍贵瞬间。"],"activities":[{"sequence":8,"day_label":"Day 8-14","day_range":"8-14","title_zh":"每日守护者任务","title_en":"The Daily Guardian's Tasks","duration":"每天约10-15分钟","content":"(任务时长：每天约10-15分钟)\n植物守护者，从今天起，你最重要的工作就是耐心和坚持。生命的变化是悄无声息的，需要你每天都用心去观察和记录。也许今天和昨天看起来没什么不同，但一周之后，奇迹可能就在不经意间发生。\n在本周的每一天，你都需要完成以下“守护者三部曲”：\n对象： 两盆植物都一样！\n内容：\n浇水： 根据土壤的干湿情况，用量杯给两盆植物浇完全相同的水量。不需要每天都浇，保持土壤微湿即可。请在日记中记录下浇水的日期和水量。\n光照： 确保两盆植物摆放在同一个位置，接受完全相同的阳光。如果需要，可以每天中午将它们调换一下左右位置，以避免窗户某一侧的光照更强。\n环境： 保持它们周围的环境一致，不要给某一盆单独施肥或改变环境。\n这是我们实验的核心变量！\n内容：\n对实验组 ❤️ (例如：[爱心植物名])：\n每天固定一个时间（比如早上或傍晚），花至少5分钟陪伴它。\n说悄悄话： 告诉它今天发生的趣事，鼓励它“快快长大”、“你是最棒的豆苗！”。\n爱的抚摸： 当它长出叶子后，可以用手指非常非常轻柔地抚摸一下它的叶片。\n意念祝福： 闭上眼睛，在心里想象它沐浴在金色的阳光里，根系发达，茎叶强壮，充满生命力的样子。\n对对照组    (例如：[叶子植物名])：\n在完成浇水等必要工作后，不要与它进行额外的互动。\n在房间里的时候，尽量不要长时间地注视它或在心里想它。把它当作一个需要维持生命的普通盆栽即可。\n对象： 两盆植物都要记录！\n内容：\n拍照/画画： 每天在同一个角度，为两盆植物分别拍一张“成长快照”，或者亲手把它们的模样画下来。这能最直观地看到变化。\n测量数据：\n身高 (cm)： 一旦植物破土而出，每天用尺子从土壤表面量到它的最高点。要非常小心，不要伤到它！\n叶片数量： 记录下完全展开的叶子有多少片。\n填写日记： 将上述所有信息，以及你对它们做了什么（悄悄话、浇水等），完整地填写到你当天的《植物观察日记》中。\n学习如何进行持续、有耐心的观察。科学发现往往不是一蹴而就的，而是源于日复一日的积累。\n练习区分“客观记录”（身高、叶片数）和“主观互动”（说悄悄话、意念祝福），并理解在我们的实验中，后者是我们想要测试的“自变量”。\n亲身体会“发芽”这一生命中最神奇的瞬间，并思考是什么力量让一颗小小的种子能够破土而出。\n本周作业将在周末（Day 14）统一提交。\n提交本周的《植物观察日记》：\n请将你本周完成的所有日记记录（大约5-7天）拍照上传。\n请确保照片清晰，能看清楚你记录的数据和图画。你可以将几页日记拼在一张图上，或分多次上传。\n提交“破土而出”的特别报告：\n在本周，你的植物很可能已经发芽了！请为你第一棵破土而出的植物，写一份特别的“出生报告”。\n在下方的文本框中，回答以下问题：\n问题1： 是哪一盆植物先发芽的？是实验组❤️还是对照组  ？它是在第几天发芽的？\n问题2： 当你看到第一抹绿色从土壤中钻出来时，你是什么心情？\n问题3（思考题）： 如果是实验组先发芽，你觉得这能证明“爱”起作用了吗？如果不是，你又作何感想？（提示：科学结论需要看最终的、长期的趋势，而不是单一的事件。）\n守护者，你做得非常棒！坚持每日的观察和记录，是这个项目中最考验耐心，也是最有价值的部分。你不仅在进行一项科学实验，更在与两个小生命建立一种深刻的连接。无论它们最终长成什么样，这段用心陪伴的经历，都将是你最宝贵的收获。下周，我们将继续我们的观察，并学习如何将一周的数据，汇集成一张直观的“生长曲线图”！"}]},{"week":3,"theme":"看见生长——绘制你的第一条生命曲线","days_range":"15-21","goals":["继续坚持每日的观察、测量、记录和差异化互动。学习“生长曲线”的概念，并将本周收集到的“身高”数据，亲手绘制成一张能够直观对比两株植物生长趋势的曲线图。"],"activities":[{"sequence":15,"day_label":"Day 15-20","day_range":"15-20","title_zh":"每日守护者任务（进阶版）","title_en":"The Daily Guardian's Tasks - Advanced","duration":"每天约15分钟","content":"(任务时长：每天约15分钟)\n植物守护者，你的两株小生命现在应该已经展现出明显的绿意了！它们可能长高了，也可能长出了更多的叶子。这一周，我们的核心任务依然是——坚持。\n请继续严格执行你的“守护者三部曲”：标准化的物理照料、差异化的心灵灌溉、以及严谨的每日记录。\n在你的植物已经有一定身高和叶片后，除了记录核心数据，请开始关注一些更细微的“生命体征”：\n叶片的颜色： 实验组❤️的叶子，是不是看起来更翠绿、更有光泽？\n茎的姿态： 实验组❤️的茎，是不是更挺拔有力？\n朝向： 两株植物是不是都同样积极地朝向阳光？还是其中一株显得更有“活力”？\n请将这些细微的观察，用文字或图画的形式，记录在你每日日记的“我的观察和感受”一栏里。这些“质性数据”将是你最终报告中非常生动的故事素材。\n练习更细致的观察能力，从“长了没”升级到“长得怎么样”。\n在与实验组植物“沟通”时，尝试分享你自己的心情。科学家们也在探索，这种双向的情感交流是否会产生更强的影响。\n本周的核心作业将在周末（Day 21）统一提交，但请务必保证每日的记录不间断。\n持续记录： 在你的《植物观察日记》中，完成本周（Day 15 - Day 20）的所有记录。"},{"sequence":21,"day_label":"Day 21","day_range":"21","title_zh":"数据可视化：绘制你的第一条生长曲线","title_en":"Data Visualization: Plotting Your First Growth Curve","duration":"约45分钟","content":"(任务时长：约45分钟)\n植物守护者，你已经连续两周，每天都在测量植物的身高。你的日记里积累了一串宝贵的数字。现在，我们要施展一种新的“数据魔法”，把这些数字变成一条会跳舞的线——“生长曲线”！\n生长曲线是生物学家最常用的工具之一。它能非常直观地告诉我们，一个生命在一段时间内长得有多快，是匀速生长，还是突然“猛蹿”了一下。\n选项A：纸笔绘制（推荐！）\n准备材料： 一张方格纸（或白纸和尺子）、两种不同颜色的彩笔（例如，红色❤️和绿色  ）。\n画坐标轴：\n在纸的左侧画一条垂直的线，这是Y轴，代表“身高（cm）”。在上面均匀地标出刻度，例如0, 1, 2, 3...\n在纸的下方画一条水平的线，这是X轴，代表“日期”。在上面均匀地标出本周的日期，例如 Day 15, Day 16, ..., Day 21。\n描点：\n实验组❤️： 拿出你的日记，找到实验组本周的身高数据。用红色笔，在图上找到对应的“日期”和“身高”的点，并画一个小圆圈。例如，Day 15身高1.5cm，就在Day 15的垂直线上，找到1.5cm的高度，点一个点。\n对照组  ： 同样，用绿色笔，在图上描出对照组本周所有身高数据对应的点。\n连线：\n用红色笔，将实验组的所有红点，按日期的顺序依次连接起来，形成一条红色的曲线。\n用绿色笔，将对照组的所有绿点连接起来，形成一条绿色的曲线。\n添加图例： 在图的旁边，画一个红色❤️并写上“[实验组植物名]”，画一个绿色  并写上“[对照组植物名]”。给你的图起一个标题，例如“第三周生长曲线对比图”。\n选项B：盖亚的图表生成器\n输入数据： 在下方的表格中，分别输入两株植物本周每天的身高数据。\n日期\n实验组❤️身高(cm)\n对照组  身高(cm)\nDay 15\n \n \nDay 16\n \n \n...\n \n \nDay 21\n \n \n[点击这里，生成我的生长曲线！]\n生成图表： 盖亚会自动为你生成一张包含两条曲线的、专业美观的生长曲线图。\n学习如何将离散的数据点，转化为连续的趋势线。\n学习如何从曲线的“斜率”（陡峭程度）来判断生长速度的快慢。曲线越陡，说明长得越快！\n提交本周的《植物观察日记》：\n将你本周（Day 15-21）的所有日记记录拍照上传。\n提交你的《生长曲线图》：\n如果你是手绘的，请将你的作品拍照上传。\n如果你使用了盖亚生成器，请将生成的图表截图上传。\n提交你的曲线解读：\n在下方的文本框中，观察你的生长曲线图，并回答以下问题：\n问题1： 在本周，哪一株植物的生长曲线看起来更“陡峭”？这意味着什么？\n问题2： 两条曲线有没有出现“交叉”？或者，它们之间的差距是在变大还是在变小？\n问题3（你的洞察）： 结合你日记中对叶片颜色、茎姿态等的观察，你觉得这张曲线图是否完整地反映了两株植物的“生命力”差异？有没有什么是曲线图无法告诉我们的？\n你已经成为一名小小的数据艺术家了！守护者，你不仅在培育生命，更在学习如何用视觉的语言来讲述生命的故事。这张小小的生长曲线图，是你进行科学分析的有力武器。它将一周的耐心观察，浓缩成了一个清晰的、充满信息的趋势。下周，我们将迎来项目的最后一周，是时候整合你所有的照片、数据和图表，撰写一份完整的《植物生长观察报告》，并准备向世界分享你和你的植物伙伴之间的悄悄话了！"}]},{"week":4,"theme":"收获的季节——分享你与植物的秘密","days_range":"22-28","goals":["整合所有观察日记、照片和生长曲线图，完成一份图文并茂、充满个人感悟的《植物生长观察报告》。准备并录制一个简短的分享视频，在全球“小小守护者论坛”上，向世界各地的同伴们展示你的研究成果。"],"activities":[{"sequence":22,"day_label":"Day 22-25","day_range":"22-25","title_zh":"成果汇集：撰写你的《植物生长观察报告》","title_en":"Harvesting Results: Crafting Your Plant Growth Report","duration":"约90分钟，可在4天内完成","content":"(任务时长：约90分钟，可在4天内完成)\n植物守护者，经过近一个月的辛勤照料和细心观察，你的办公桌上已经堆满了宝贵的“证据”——每日的照片、详细的日记、以及清晰的生长曲线。现在，是时候把它们编织在一起，创作出你在这个项目中的最终“作品”了！\n你的《植物生长观察报告》将是你本次探险的完美总结。请确保它包含以下几个部分，你可以用画画和文字结合的方式来完成。\n第一部分：我的实验伙伴 (My Experiment Partners)\n内容：\n贴上你的实验组植物❤️和对照组植物  最精神的一张“合影”。\n写下它们的最终档案：名字、品种、以及从播种到现在的总天数。\n第二部分：生长之旅全记录 (The Full Journey of Growth)\n内容：\n生长曲线总图： 将你每周绘制的生长曲线图整合起来，或者让盖亚为你生成一张包含所有日期的、完整的总生长曲线图。\n数据总结： 在图表下方，填写最终的数据对比：\n最终身高： 实验组 [ ] cm vs. 对照组 [ ] cm。\n最终叶片数： 实验组 [ ] 片 vs. 对照组 [ ] 片。\n图片故事： 挑选最有代表性的几张每日照片（例如：刚发芽时、第一对真叶长出时、以及现在的样子），制作一个“成长故事”对比图板。\n第三部分：我的核心发现 (My Core Findings)\n内容： 这是你作为“首席科学家”下结论的地方！请回答：\n问题1： 综合所有数据（身高、叶片数）和你的日常观察（颜色、姿态），你认为实验组植物和对照组植物在生长上是否存在明显的差异？\n问题2： 如果存在差异，你认为这种差异是由什么引起的？是你付出的“爱的关注”吗？还是可能有其他我们没有想到的原因？\n第四部分：守护者的悄悄话 (The Guardian's Whisper)\n内容： 这是你分享个人感悟的部分。请完成下面的句子：\n“通过这次实验，我最大的感受是……”\n“我想对我的实验组植物 [植物名]❤️ 说……”\n“我也想对我的对照组植物 [植物名]   说……”\n“我认为，所有的生命，无论是动物还是植物，可能都……”\n学习如何将多周的、连续的数据进行整合与最终呈现。\n练习如何基于数据和观察，得出一个初步的、但有理有据的结论。\n学习如何将科学探索与个人情感和感悟相结合，并进行真诚的表达。\n提交你的《植物生长观察报告》：\n请将你制作完成的、包含所有四个部分的完整报告，以拍照或截图的形式上传。\n如果你是用纸笔创作的，我们鼓励你用彩笔进行美化，让它成为一份艺术品！"},{"sequence":26,"day_label":"Day 26-28","day_range":"26-28","title_zh":"分享你的故事：录制“守护者”视频","title_en":"Sharing Your Story: Recording Your 'Guardian' Video","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n植物守护者，你已经完成了一份出色的书面报告。现在，让我们用一种更生动、更温暖的方式，来分享你的故事。你需要录制一个1-2分钟的短视频，在全球“小小守护者论坛”上播放。\n你的视频可以很简单，用爸爸妈妈的手机就能拍。但内容要包含以下几个要点：\n开场（15秒）：\n出镜： 抱着或站在你的两盆植物旁边，向大家问好。\n台词： “大家好，我是‘植物的悄悄话’项目的守护者[你的名字]！这是我的实验伙伴，[实验组植物名]❤️和[对照组植物名]  。”\n展示核心发现（45秒）：\n展示： 将你的镜头对准你报告里的“生长曲线总图”或“成长故事”图板。\n台词： “在一个月的时间里，我每天都给[实验组名]❤️说悄悄话，而只是给[对照组名]  浇水。你们看，这是它们的生长曲线！红色的线明显比绿色的线要高。最后，它的身高多了[X]厘米！”（请根据你的真实结果来讲述）\n分享你的感悟（45秒）：\n出镜： 再次回到你和植物的画面。\n台词： “这次实验让我觉得，植物真的能感受到我们的爱。也许我们说的每一句好话，都会变成它们生长的阳光。我认为，我们应该用爱对待身边的每一个生命。谢谢大家！”\n最后的彩蛋：\n视频的最后，你可以加上一个你抚摸实验组植物叶子的特写镜头，或者一个你和两盆植物的温暖合影。\n学习如何将书面报告的核心内容，转化为简洁、有吸引力的口头语言。\n练习在镜头前自然、自信地进行表达。\n上传你的“守护者分享视频”：\n请将你录制好的1-2分钟短视频文件上传。\n提交你的结业宣言：\n在下方的“结业留言板”上，为你自己这一个月的旅程，画上一个圆满的句号。\n格式： “我是守护者[你的名字]。我的植物[实验组名]❤️比[对照组名]  多长高了[X]厘米！我最大的收获是明白了耐心和爱才是最好的肥料。#伊卡洛斯结业#”\n伟大的植物守护者，为你自己鼓掌！你不仅完成了一次严谨的科学对照实验，更亲手培育、见证了生命的成长与奇迹。你用自己的行动，探索了意识与生命之间那条看不见的、温暖的纽带。你所提交的报告和视频，将激励更多的人去关爱身边的每一个微小生命。你已经获得了“伊卡洛斯计划-植物守护者”的认证！希望你能继续照顾你的两位植物伙伴，并带着这份爱与好奇，在我们下一个模块的探险中再会！"}]}]$week_data$::jsonb
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 4;

-- 验证更新
SELECT
  sequence_number,
  title,
  jsonb_array_length(week_plan) as weeks_count,
  (
    SELECT COUNT(*)
    FROM jsonb_array_elements(week_plan) w,
         jsonb_array_elements(w->'activities') a
  ) as activities_count
FROM course_contents
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 4;
